{
  "name": "NC Senior Health Insurance Information Program (SHIIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income or asset limits; open to all Medicare beneficiaries, their families, and caregivers. Counselors assist with eligibility screening for related programs like Extra Help and Medicare Savings Programs, which have separate income/asset tests (specific limits not detailed in SHIIP sources; contact counselor for current thresholds).[1][4][5]",
    "asset_limits": "No asset limits for SHIIP itself. For programs like Extra Help and Medicare Savings Programs that SHIIP helps screen for, limited income/assets apply but details vary and are not specified here.[5]",
    "other_requirements": ["Must be a Medicare beneficiary, caregiver, or family member with Medicare-related questions. Available to residents of all 100 NC counties. No requirement to be low-income."][1][3][4]
  },
  "benefits": {
    "type": "service",
    "value": "Free, unbiased, personalized counseling on Medicare (Parts A, B, C, D), Medicare supplements, Medicare Advantage, prescription drug plans, long-term care insurance, other health insurance concerns, Medicare costs assistance programs (e.g., Extra Help, Medicare Savings Programs), fraud/waste/abuse reporting, and plan comparisons. Provided one-on-one by trained counselors (not licensed agents; do not sell or endorse plans). No fixed hours/dollars; counseling duration as needed per session.[1][3][4][5]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Toll-free 1-855-408-1212 (Mon-Fri 8am-5pm) or local (919) 807-6900.[1][2][4][6]", "Website: https://www.ncdoi.gov/consumers/medicare-and-seniors-health-insurance-information-program-shiip or https://www.ncshiip.com (find counselor by county, schedule counseling).[1][2][4]", "Email: Melinda.Munden@ncdoi.gov or local counselor email (e.g., shiip@senior-resources-guilford.org).[1][3]", "In-person or local phone: Search by county on NC DOI site for regional counselors (e.g., Guilford: (336) 884-4816 or (336) 373-4816; BSRI: (910) 754-2300).[3][4][5]"],
    "processing_time": "Immediate phone counseling available Mon-Fri 8am-5pm; appointments scheduled as needed (no formal processing).[1][6]",
    "waitlist": null,
    "forms": ["No specific application forms required; counselors guide through Medicare forms if needed (e.g., for Extra Help)."],
    "documents": ["Medicare card, current insurance details (supplements, Advantage, Part D plans), prescription list, income/asset info if screening for savings programs. Prepare questions about specific plans."[3][4][5]]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available in all 100 North Carolina counties.[4]",
    "regional_variations": "Counseling delivered through local counselors/regional providers (e.g., Senior Resources Guilford, BSRI); different local phone numbers and offices by county, but services uniform statewide. Find by county on NC DOI site.[3][4][5]",
    "offices_or_providers": ["Central: NC Department of Insurance, 1201 Mail Service Center, Raleigh NC 27699-1201.[1]", "Examples: Guilford County via senior-resources-guilford.org[3], Southeastern NC via bsrinc.org[5]; full list by county at https://www.ncdoi.gov[4]"]
  },
  "official_source": "https://www.ncdoi.gov/consumers/medicare-and-seniors-health-insurance-information-program-shiip[4]",
  "gotchas": ["SHIIP counselors are not licensed agents and do not sell/endorses plans—contact your agent for plan-specific changes.[3][4]", "Not direct financial aid; provides counseling to help qualify for programs like Extra Help (people miss screening opportunities).[5]", "For plan complaints or company issues, contact insurer directly first.[4]", "Volunteers provide service; availability may depend on local counselor schedules.[4]"],
  "data_shape_notes": "no income test; counseling-only service (not benefits/funds); delivered via 100-county local counselor network with uniform core services but regional contacts; helps access separate Medicare savings programs with income/asset tests"
}

{
  "name": "NC Senior Community Service Employment Program (SCSEP)",
  "eligibility": {
    "age": 55,
    "income_limits": "Family income no more than 125% of the federal poverty level (varies by family size; exact dollar amounts change annually with federal poverty guidelines—check current HHS poverty guidelines for NC household table, e.g., for 2026, consult ASPE.hhs.gov/poverty-guidelines)",
    "asset_limits": null,
    "other_requirements": ["Unemployed", "U.S. citizen or authorized to work", "Priority: veterans and qualified spouses first, then over 65, disability, low literacy/limited English proficiency, rural resident, homeless/at risk, low employment prospects, failed American Job Center services, formerly incarcerated"]
  },
  "benefits": {
    "type": "employment",
    "value": "Part-time paid community service job training (average 20 hours/week at highest of federal/state/local minimum wage); on-the-job training in roles like child care, customer service, teachers' aide, computer technician, maintenance, health care; skills training (e.g., computer); job placement assistance to unsubsidized employment; typically 6 months training",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Contact NC DHHS Division of Aging and Adult Services (specific phone/website via ncdhhs.gov/divisions/aging); local grantees like NCBA (ncbainc.org/scsep), Mid-Carolina Regional Council (mccog.org/scsep); American Job Centers; phone not specified—call NC 211 or local provider", "In-person at community nonprofits/public agencies (schools, hospitals, senior centers)", "Multiple routes via 19 national grantees/state agencies including NC operators"],
    "processing_time": "Not specified; training starts after eligibility determination, typically leads to 6 months placement",
    "waitlist": "Possible due to funding limits and transitions; varies by grantee/community availability",
    "forms": ["No specific form named; intake via grantee application"],
    "documents": ["Proof of age (ID)", "Proof of income (tax returns, pay stubs)", "Proof of unemployment", "Veteran status if applicable", "Residency proof"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None statewide; available where grantees operate",
    "regional_variations": "Administered by local grantees (e.g., NCBA, Mid-Carolina Regional Council, CWI Works); different providers, host sites, wait times by region/community demand",
    "offices_or_providers": ["NC DHHS Division of Aging (ncdhhs.gov/divisions/aging/senior-community-services-employment-program)", "NCBA (ncbainc.org/scsep)", "Mid-Carolina Regional Council (mccog.org/scsep)"]
  },
  "official_source": "https://www.ncdhhs.gov/divisions/aging/senior-community-services-employment-program",
  "gotchas": ["Income limit strictly 125% FPL—no asset test but proof required", "Temporary bridge program (avg 6 months) to unsubsidized work—not permanent job", "Priority tiers limit access for non-priority applicants", "Funding delays/transitions may cause waitlists or slots", "Must be unemployed and seeking work—not retirement income support", "Paid at minimum wage only"],
  "data_shape_notes": "Grantee-administered with priority tiers; income scales by household size at 125% FPL; regional providers determine slots/wait times; no fixed asset limits"
}

{
  "name": "NC Legal Assistance for Older Adults",
  "eligibility": {
    "age": 60,
    "income_limits": "No income limits; clients age 60 or older are exempt from income limitations and eligible for services[1][2][3][8]",
    "asset_limits": "No asset limits mentioned; eligibility based on age with priority for greatest economic or social need[1][2][3]",
    "other_requirements": ["Priority given to seniors with the greatest economic or social need[1][2][3][5]", "Does not serve prisoners[1]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free civil legal help including: wills and powers of attorney; public benefits (Medicaid, food stamps/SNAP, SSI, SSDI, Veteran's benefits); abuse and neglect; unemployment compensation; housing (foreclosure, eviction, subsidized housing, repairs, utilities); consumer issues; wrongful repossession. Services include answering legal questions, advice, writing letters, phone calls, document review, and referrals to local offices or pro bono attorneys[2][3][5]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: Toll-free Senior Legal Helpline 1-877-579-7562 (9:00 AM–11:00 AM & 1:00 PM–3:00 PM, Monday-Friday)[1][2][3][5][8]", "Online: Apply via JusticeHub client portal at legalaidnc.org[7]", "Website: legalaidnc.org/project/senior-law-project/ or www.legalaidnc.org[1][2][3]"],
    "processing_time": "Not specified in sources",
    "waitlist": null,
    "forms": ["No specific form name/number; apply via phone, online JusticeHub intake, or website[1][2][7]"],
    "documents": ["Not specified; prepare details on legal issue for intake[2][5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available to North Carolinians statewide via toll-free helpline[1][2][3][5]",
    "regional_variations": "Operates statewide but may refer to local Legal Aid offices; some Area Agencies on Aging (e.g., High Country) contract with the project, but core service is uniform[5]",
    "offices_or_providers": ["Legal Aid of North Carolina Senior Law Project statewide; local offices for follow-up referrals (e.g., Asheville office)[1][5]"]
  },
  "official_source": "https://legalaidnc.org/project/senior-law-project/[3]",
  "gotchas": ["Priority for those with greatest economic/social need may mean non-priority cases receive referrals rather than direct representation[2][3][5]", "Specific intake hours (9-11 AM, 1-3 PM M-F); call during those times[2][5]", "Excludes prisoners; not for those under 60 (separate line: 1-866-219-5262)[1][5]", "Free but civil matters only, focused on basic needs like safety, shelter, income[2][3]"],
  "data_shape_notes": "no income test; age 60+ exempt from financial eligibility; statewide helpline with priority tiers; services via advice, letters, referrals rather than full representation for all"
}

{
  "name": "NC Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available to all residents, families, and concerned parties regardless of financial status.",
    "asset_limits": "No asset limits or tests apply.",
    "other_requirements": ["Resides (or loved one resides) in a qualifying long-term care facility in North Carolina, including nursing homes, adult care homes, family care homes, multiunit assisted housing with services, continuing care retirement communities (CCRCs), or independent living (rental) communities for seniors and disabled adults.", "Open to current/former residents, families, individuals seeking facilities, advocacy groups, and facility staff with concerns.", "No age requirement for receiving assistance; program serves adults in long-term care."]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Advocacy to resolve complaints about resident rights, quality of care/life; investigation of grievances; mediation with facilities; education on rights, elder abuse prevention/detection/reporting; monitoring of federal/state/local laws; facility visits (e.g., nursing homes every 3 months, adult care homes every 3 months, family care homes annually); confidential services at no cost.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone or contact local regional office via county list (specific numbers vary by county; statewide info at NCDHHS site).", "In-person or visit to one of 16 regional offices housed in Area Agencies on Aging.", "Provide details verbally or in writing: resident name/address, age/birthdate, caregiver name, situation explanation, mental/physical condition."],
    "processing_time": "Initial consultation provided promptly upon contact; no formal processing time specified as it's complaint-resolution based.",
    "waitlist": null,
    "forms": ["No specific application forms required; submit complaint details directly to ombudsman."],
    "documents": ["Resident name/address, age/birthdate, caregiver name (if any), description of situation/concern, mental/physical condition details."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Services tied to 100 counties via 16 regional offices; contact based on county of facility/residence.",
    "regional_variations": "Administered by 16 regional offices (housed in Area Agencies on Aging) with local Community Advisory Committees (CACs) appointed by county commissioners; CACs conduct facility visits and report locally; specific contacts/offices vary by region (e.g., Albemarle Commission, Kerr Tar COG, Land of Sky, Central Pines, Piedmont Triad).",
    "offices_or_providers": ["16 Regional Long-Term Care Ombudsman Offices", "Statewide Office of the State Long-Term Care Ombudsman", "Local Community Advisory Committees (CACs) per county/region"]
  },
  "official_source": "https://www.ncdhhs.gov/divisions/aging/long-term-care-ombudsman",
  "gotchas": ["Not a financial aid, healthcare, or Medicaid program—purely advocacy/complaint resolution; no direct services like care or funding.", "Abuse/neglect reports go to NC Division of Health Service Regulation or law enforcement, not solely ombudsman.", "Review admission agreements carefully, especially arbitration clauses—consult attorney before signing.", "Services are confidential and free, but ombudsmen cannot act if resident refuses involvement.", "For Medicaid/long-term care funding, apply separately via local DSS; ombudsman can assist in facility selection but not approval.", "Volunteering as CAC member has strict requirements (e.g., 18+, local residency, no conflicts of interest, 36-hour training)."],
  "data_shape_notes": "no income/asset test; advocacy-only for long-term care facility residents/families; delivered via 16 regional offices + local CACs with county-specific appointments/visits; complaint-driven, not enrollment-based"
}

{
  "name": "North Carolina Seniors Farmers' Market Nutrition Program",
  "eligibility": {
    "age": 60,
    "income_limits": "Household income at or below 185% of the Federal Poverty Level. Monthly limits: $2,413 for 1-person household; $3,261 for 2-person household. Larger household sizes follow 185% FPL scale (specific amounts for 3+ not detailed in sources).[1][2][3][5]",
    "asset_limits": "No asset limits mentioned in program sources.[1][2][3][5]",
    "other_requirements": ["Must live in a county with a participating local agency.", "Must apply through local agency serving that county."][2]
  },
  "benefits": {
    "type": "in_kind",
    "value": "$50 in vouchers per eligible senior, issued as a booklet of 10 vouchers worth $5 each. Vouchers can buy fresh NC-grown fruits, vegetables, fresh-cut herbs, and raw honey only (excludes nuts, seeds, eggs, meat, cheese, jams, plants, etc.). Usable July 1–September 30 at certified farmers' markets, roadside stands, or CSAs. No change given.[1][3][5][6]",
    "varies_by": "fixed"
  },
  "application": {
    "methods": ["Fill out NC SFMNP Voucher Interest Form to join interest list (notified in June of local agency contacts); contact local agency for eligibility screening and voucher distribution (varies by county, e.g., Charlotte-Mecklenburg Food Policy Council in Mecklenburg at charlottefoodpolicy.com/seniorvouchers); in-person registration at some markets (e.g., July 5, 19, Aug 2, 16 at Uptown Farmers Market).[2][5]", "Phone/website/mail not specified centrally; use local agency contacts provided after interest form.[2]"],
    "processing_time": "Enrollment opens July 1 (e.g., 2025); applications handled locally starting then. Interest list notifications in June.[1][2][5]",
    "waitlist": "Possible due to limited funding/participation; not explicitly detailed but implied by county-specific enrollment events and interest list.[2][5]",
    "forms": ["2025 NC SFMNP Voucher Interest Form (pre-application interest list). Specific application forms handled by local agencies.[2]"],
    "documents": ["Proof of age (60+), income (showing ≤185% FPL), and county residency. Proof of enrollment in SNAP/CSFP may qualify in some cases.[2][6]"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Only in counties with participating local agencies (e.g., Mecklenburg in 2024/2025; not all NC counties; check map or interest form for current list).[2][3][5]",
    "regional_variations": "Administered by local agencies (e.g., Charlotte-Mecklenburg Food Policy Council and Mecklenburg DSS in Mecklenburg County; different markets and registration dates per area). Participating markets vary (e.g., Charlotte Regional, Matthews, Uptown in Mecklenburg).[1][3][5]",
    "offices_or_providers": ["NC DHHS Division of Aging (state lead); local examples: Charlotte-Mecklenburg Food Policy Council (Mecklenburg), Mecklenburg County DSS.[3][5]"]
  },
  "official_source": "No single central .gov application page identified; state lead via NC DHHS Division of Aging (implied); local info at charlottefoodpolicy.com/seniorvouchers or triangleonthecheap.com for examples. USDA overview: fns.usda.gov/sfmnp.[3][4][5]",
  "gotchas": ["Not available in all counties—must confirm participating county via interest form.", "Summer-only (July 1–Sept 30); enrollment starts July 1, so act fast.", "Vouchers only for specific NC-grown items; no change given—spend full $5 increments.", "One booklet per eligible senior, not per household.", "Residency in participating county required, even if 60+ and income-eligible.", "Interest form is not the application—leads to local agency.[1][2][5]"],
  "data_shape_notes": "County-restricted with local agency administration; fixed $50 benefit; 185% FPL income test; summer seasonal only; no asset test; varies by participating markets per region."
}
